pragma solidity 0.8.26;

import {ITypeAndVersion} from "@chainlink/contracts/src/v0.8/shared/interfaces/ITypeAndVersion.sol";
import {IAuctionCallback} from "src/interfaces/IAuctionCallback.sol";
